import json
from typing import Any, List, Optional, Union

def _extract_rows(raw: Union[dict, list]) -> List[dict]:
    """
    Normalise the incoming payload to a flat list of row dictionaries.

    Parameters
    ----------
    raw : dict | list
        The original payload – either an array of rows or a wrapped object
        that contains a JSON string in `content[0].text`.

    Returns
    -------
    List[dict]
        List of row dictionaries (e.g. [{"loan_id": 2, "status": "ACTIVE", …}, …])
    """
    # 1️⃣ Plain array – already a list of dicts
    if isinstance(raw, list):
        return raw

    # 2️⃣ Wrapped object with `content` → `text` JSON string
    if isinstance(raw, dict):
        # Guard against missing keys
        content = raw.get("content")
        if isinstance(content, list) and len(content) > 0:
            first = content[0]
            if isinstance(first, dict) and first.get("type") == "text":
                json_str = first.get("text", "")
                try:
                    # The string itself is JSON; decode it
                    inner = json.loads(json_str)
                    # The problem statement mentions the rows are under the key "rows"
                    rows = inner.get("rows", [])
                    if isinstance(rows, list):
                        return rows
                except json.JSONDecodeError:
                    raise ValueError("Unable to parse JSON string inside content.text")
    # If we reach here, we couldn't find any rows
    return []

def find_first_active_loan_id(payload: Union[dict, list]) -> Optional[int]:
    """
    Return the loan_id of the first contract with status == "ACTIVE".
    If none is found, return None.

    Parameters
    ----------
    payload : dict | list
        The raw JSON payload received from the upstream service.

    Returns
    -------
    int | None
        The loan_id of the first ACTIVE contract, or None when no match exists.
    """
    rows = _extract_rows(payload)

    for row in rows:
        # Defensive: make sure keys exist and are of expected type
        if row.get("status") == "ACTIVE":
            return row.get("loan_id")    # could be None if the key is missing
    return None

